from flask import Flask, redirect, request, url_for, session
import requests
import jwt

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Configuration
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_ENDPOINT = 'https://your-oidc-provider.com/auth'
TOKEN_ENDPOINT = 'https://your-oidc-provider.com/token'
USERINFO_ENDPOINT = 'https://your-oidc-provider.com/userinfo'
REDIRECT_URI = 'http://localhost:5000/callback'
SCOPE = 'openid'

@app.route('/')
def home():
    if 'id_token' in session:
        return 'Logged in as: {}'.format(session['userinfo'])
    return 'You are not logged in. <a href="/login">Login</a>'

@app.route('/login')
def login():
    authorization_url = (
        f"{AUTHORIZATION_ENDPOINT}?response_type=id_token&client_id={CLIENT_ID}"
        f"&redirect_uri={REDIRECT_URI}&scope={SCOPE}"
    )
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    if not id_token:
        return 'Error: No id_token provided', 400

    try:
        # Decode the ID token
        decoded_id_token = jwt.decode(id_token, options={"verify_signature": False})
        session['id_token'] = id_token
        session['userinfo'] = decoded_id_token['sub']
    except jwt.ExpiredSignatureError:
        return 'Error: ID token has expired', 400
    except jwt.InvalidTokenError:
        return 'Error: Invalid ID token', 400

    return redirect(url_for('home'))

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(debug=True)